const idsResp = await fetch('https://hacker-news.firebaseio.com/v0/topstories.json');
const ids = await idsResp.json();
const top20 = ids.slice(0, 20);
const stories = await Promise.all(top20.map(async (id) => {
  const r = await fetch('https://hacker-news.firebaseio.com/v0/item/' + id + '.json');
  return r.json();
}));
return JSON.stringify(stories.map((s, i) => ({
  rank: i + 1,
  title: s.title,
  score: s.score,
  author: s.by,
  comments: s.descendants || 0,
  url: s.url || ('https://news.ycombinator.com/item?id=' + s.id),
})));

(async function() {
  try {
    var resp = await fetch('/api/topics/hot.json');
    var data = await resp.json();
    return data.map(function(t, i) {
      return {rank: i+1, title: t.title, node: t.node ? t.node.title : '', replies: t.replies, url: t.url};
    });
  } catch(e) {
    var items = document.querySelectorAll('.cell.item');
    var list = [];
    items.forEach(function(el, i) {
      var a = el.querySelector('.item_title a');
      var node = el.querySelector('.node');
      if (a) list.push({rank: i+1, title: a.textContent.trim(), node: node ? node.textContent.trim() : '', url: 'https://www.v2ex.com' + a.getAttribute('href')});
    });
    return list.slice(0, 30);
  }
})()

var rows = document.querySelectorAll('article.Box-row, [class*="Box-row"]');
var list = [];
rows.forEach(function(row, i) {
  var repoLink = row.querySelector('h2 a, h1 a');
  var desc = row.querySelector('p');
  var lang = row.querySelector('[itemprop="programmingLanguage"], span[class*="repo-language-color"] + span');
  var stars = row.querySelector('a[href*="/stargazers"], span.d-inline-block');
  if (repoLink) {
    var href = repoLink.getAttribute('href');
    list.push({
      rank: i + 1,
      repo: href.replace(/^\//, ''),
      description: desc ? desc.textContent.trim() : '',
      language: lang ? lang.textContent.trim() : '',
      stars: stars ? stars.textContent.trim() : '',
      url: 'https://github.com' + href,
    });
  }
});
return JSON.stringify(list);

var links = document.querySelectorAll('a[href^="/posts/"]');
var seen = {};
var list = [];
links.forEach(function(a) {
  var href = a.getAttribute('href');
  if (!href || href.includes('/reviews') || seen[href]) return;
  seen[href] = true;
  var name = a.textContent.trim();
  if (!name || name.length > 100) return;
  list.push({
    rank: list.length + 1,
    name: name,
    url: 'https://www.producthunt.com' + href,
  });
});
return JSON.stringify(list.slice(0, 20));

const resp = await fetch('https://api.stackexchange.com/2.3/questions?order=desc&sort=hot&site=stackoverflow&pagesize=25');
const data = await resp.json();
return JSON.stringify(data.items.map((q, i) => ({
  rank: i + 1,
  title: q.title,
  score: q.score,
  answers: q.answer_count,
  tags: q.tags.slice(0, 3).join(', '),
  url: q.link,
})));

(async function() {
  try {
    var resp = await fetch('/top.json?per_page=25&period=weekly');
    var data = await resp.json();
    var topics = data.topic_list.topics;
    return topics.map(function(t, i) {
      return {rank: i+1, title: t.title, replies: t.posts_count - 1, likes: t.like_count, views: t.views, url: 'https://linux.do/t/topic/' + t.id};
    });
  } catch(e) {
    var rows = document.querySelectorAll('tr.topic-list-item');
    var list = [];
    rows.forEach(function(row, i) {
      var a = row.querySelector('.main-link a.title');
      var replies = row.querySelector('.num.posts span');
      var views = row.querySelector('.num.views span');
      if (a) list.push({rank: i+1, title: a.textContent.trim(), replies: replies ? parseInt(replies.textContent) : 0, views: views ? views.textContent.trim() : '', url: 'https://linux.do' + a.getAttribute('href')});
    });
    return list.slice(0, 25);
  }
})()

var items = document.querySelectorAll('.hot-list-item, [class*="HotList"], [class*="hot-item"]');
if (!items.length) items = document.querySelectorAll('a[href*="/post/"]');
var seen = {};
var list = [];
items.forEach(function(el, i) {
  var titleEl = el.querySelector('.article-title, [class*="title"], .hot-list-item-title');
  var hotEl = el.querySelector('[class*="hot"], [class*="count"]');
  var linkEl = el.querySelector('a[href*="/post/"]') || (el.tagName === 'A' ? el : null);
  var title = titleEl ? titleEl.textContent.trim() : (el.textContent || '').trim().slice(0, 60);
  if (title && !seen[title]) {
    seen[title] = true;
    list.push({
      rank: list.length + 1,
      title: title,
      hot: hotEl ? hotEl.textContent.trim() : '',
      url: linkEl ? linkEl.href : '',
    });
  }
});
return JSON.stringify(list.slice(0, 30));

var items = document.querySelectorAll('.crayons-story');
var list = [];
items.forEach(function(el, i) {
  var t = el.querySelector('.crayons-story__title a, h2 a');
  var u = el.querySelector('.crayons-story__meta a');
  if (t) list.push({rank: i+1, title: t.textContent.trim(), url: t.href, author: u ? u.textContent.trim() : ''});
});
return JSON.stringify(list.slice(0, 30));

var items = document.querySelectorAll('.story');
var list = [];
items.forEach(function(el, i) {
  var t = el.querySelector('.link a, .u-url');
  var s = el.querySelector('.score');
  if (t) list.push({rank: i+1, title: t.textContent.trim(), url: t.href, score: s ? s.textContent.trim() : ''});
});
return JSON.stringify(list.slice(0, 30));

var items = document.querySelectorAll('article.overview-card-wrapper, [class*="ModelCard"]');
var list = [];
items.forEach(function(el, i) {
  var t = el.querySelector('h4, [class*="card-title"]');
  var a = el.querySelector('a');
  var d = el.querySelector('[class*="downloads"], [title*="downloads"]');
  if (t) list.push({rank: i+1, name: t.textContent.trim(), url: a ? a.href : '', downloads: d ? d.textContent.trim() : ''});
});
return JSON.stringify(list.slice(0, 30));

var items = document.querySelectorAll('#dlpage dt, .list-identifier');
var titles = document.querySelectorAll('#dlpage dd .list-title, .mathjax');
var list = [];
var dts = document.querySelectorAll('#dlpage dt');
var dds = document.querySelectorAll('#dlpage dd');
for (var i = 0; i < Math.min(dts.length, 30); i++) {
  var link = dts[i].querySelector('a[href*="/abs/"]');
  var titleEl = dds[i] ? dds[i].querySelector('.list-title') : null;
  if (link && titleEl) {
    list.push({rank: i+1, title: titleEl.textContent.replace('Title:','').trim(), url: 'https://arxiv.org' + link.getAttribute('href')});
  }
}
return JSON.stringify(list);

var items = document.querySelectorAll('.explore-repo__list .item, .project-list .project');
var list = [];
items.forEach(function(el, i) {
  var t = el.querySelector('.project-title a, .title a, h3 a');
  var d = el.querySelector('.project-desc, .desc, p');
  var s = el.querySelector('[class*="star"], .stars-count');
  if (t) list.push({rank: i+1, name: t.textContent.trim(), url: t.href, description: d ? d.textContent.trim() : '', stars: s ? s.textContent.trim() : ''});
});
return JSON.stringify(list.slice(0, 30));

(async function() {
  for (var i = 0; i < 15; i++) {
    if (document.querySelectorAll('[class*="feed-item"], [class*="discuss-item"], .nk-list-item, a[href*="/discuss/"]').length > 2) break;
    await new Promise(function(r){setTimeout(r, 500);});
  }
  var list = [], seen = {};
  document.querySelectorAll('a[href*="/discuss/"], a[href*="/feed/main/detail/"]').forEach(function(a) {
    var title = a.textContent.replace(/\s+/g,' ').trim();
    var href = a.href || a.getAttribute('href') || '';
    if (!title || title.length < 6 || title.length > 150 || seen[title]) return;
    if (/^\d+$/.test(title) || title === '讨论' || title === '查看') return;
    seen[title] = true;
    if (!href.startsWith('http')) href = 'https://www.nowcoder.com' + href;
    list.push({rank: list.length+1, title: title, url: href});
  });
  return list.slice(0, 30);
})()

var items = document.querySelectorAll('[class*="PostsItem"]');
var list = [];
items.forEach(function(el, i) {
  var t = el.querySelector('a[class*="PostsTitle"], [class*="title"] a');
  var k = el.querySelector('[class*="karma"]');
  if (t && list.length < 20) list.push({rank: list.length+1, title: t.textContent.trim(), url: t.href, karma: k ? k.textContent.trim() : ''});
});
return JSON.stringify(list);

var items = document.querySelectorAll('[data-testid="results-list"] > div, .Box-row, .repo-list-item, [class*="search-title"]');
var list = [];
items.forEach(function(el) {
  var t = el.querySelector('a[href*="/"] span, a.v-align-middle, a[class*="prc-Link"], .search-title a');
  if (!t) t = el.querySelector('a[href*="/"]');
  var d = el.querySelector('p, [class*="description"], .search-match');
  var star = '';
  var s = el.querySelector('[class*="octicon-star"], svg.octicon-star');
  if (s && s.parentElement) star = s.parentElement.textContent.replace(/\s+/g,'').trim();
  if (t && list.length < 20) list.push({rank: list.length+1, name: t.textContent.replace(/\s+/g,' ').trim(), url: t.closest('a') ? t.closest('a').href : (t.href || ''), description: d ? d.textContent.trim().slice(0,120) : '', stars: star});
});
return list;
